head.script:
tailwind.config = {
  theme: {
    extend: {
      colors: {
        slate: {
          850: '#151d30',
          950: '#020617',
        },
        cyan: {
          450: '#22d3ee',
        }
      },
      fontFamily: {
        sans: ['Inter', 'sans-serif'],
        mono: ['JetBrains Mono', 'monospace'],
        display: ['Space Grotesk', 'sans-serif'],
      }
    }
  }
}

head.b:skin:
/* Essential Blogger overrides so the custom portfolio covers the entire page layout */
#navbar-iframe, .navbar, .header-outer, .header-cap, .header-inner, .footer-outer, .sidebar-container {
  display: none !important;
  height: 0 !important;
  visibility: hidden !important;
  margin: 0 !important;
  padding: 0 !important;
}
body {
  background-color: #020617 !important;
  margin: 0 !important;
  padding: 0 !important;
  font-family: 'Inter', sans-serif;
}
/* Prevent blogger default CSS wrapping classes from adding spacing, margins or paddings */
.content-outer, .content-inner, .main-outer, .main-inner, .columns, .columns-inner,
.column-center-outer, .column-center-inner, .post-outer, .post, .post-body,
.blog-posts, .feed-links, .comments, .section, .widget, .page_body {
  background: transparent !important;
  border: none !important;
  box-shadow: none !important;
  padding: 0 !important;
  margin: 0 !important;
  max-width: none !important;
}
/* Custom Webkit scrollbar for premium aesthetic */
::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}
::-webkit-scrollbar-track {
  background: #020617;
}
::-webkit-scrollbar-thumb {
  background: #0f172a;
  border: 2px solid #020617;
  border-radius: 8px;
}
::-webkit-scrollbar-thumb:hover {
  background: #06b6d4;
}

