            this.$watch('activeExpId', () => this.$nextTick(() => lucide.createIcons()));
            this.$watch('loadLevel', () => this.$nextTick(() => lucide.createIcons()));
          },
          scrollTo(selector) {
            const el = document.querySelector(selector);
            if (el) el.scrollIntoView({ behavior: 'smooth' });
          }
        }
